Use a hash map to store complements. For each num, check if (target - num) exists in the map. If yes, return indices. Time: O(n), Space: O(n).

def twoSum(nums, target):
    seen = {}
    for i, num in enumerate(nums):
        comp = target - num
        if comp in seen:
            return [seen[comp], i]
        seen[num] = i

def fizzBuzz(n):
    result = []
    for i in range(1, n + 1):
        if i % 15 == 0: result.append('FizzBuzz')
        elif i % 3 == 0: result.append('Fizz')
        elif i % 5 == 0: result.append('Buzz')
        else: result.append(str(i))
    return result

Use a stack. Push opening brackets. For closing, check if stack top matches.

def isValid(s):
    stack = []
    mapping = {')': '(', '}': '{', ']': '['}
    for char in s:
        if char in mapping:
            if not stack or stack[-1] != mapping[char]: return False
            stack.pop()
        else:
            stack.append(char)
    return len(stack) == 0

Use two pointers for each array, compare and append smaller element.

def merge(a, b):
    result = []
    i = j = 0
    while i < len(a) and j < len(b):
        if a[i] <= b[j]:
            result.append(a[i]); i += 1
        else:
            result.append(b[j]); j += 1
    result.extend(a[i:])
    result.extend(b[j:])
    return result

Use math: expected sum - actual sum, or XOR approach.

def missingNumber(nums):
    n = len(nums)
    return n * (n + 1) // 2 - sum(nums)

Use two pointers: slow for unique position, fast to scan.

def removeDuplicates(nums):
    if not nums: return 0
    slow = 0
    for fast in range(1, len(nums)):
        if nums[fast] != nums[slow]:
            slow += 1
            nums[slow] = nums[fast]
    return slow + 1

Use a hash map (dictionary) to count occurrences.

def charCount(s):
    freq = {}
    for c in s:
        freq[c] = freq.get(c, 0) + 1
    return freq

def findMax(arr):
    if not arr: return None
    maximum = arr[0]
    for num in arr[1:]:
        if num > maximum:
            maximum = num
    return maximum

Sort both strings and compare, or use character frequency counting.

def isAnagram(s, t):
    if len(s) != len(t): return False
    count = {}
    for c in s: count[c] = count.get(c, 0) + 1
    for c in t:
        if c not in count or count[c] == 0: return False
        count[c] -= 1
    return True

A power of two has exactly one bit set: n & (n-1) == 0.

def isPowerOfTwo(n):
    return n > 0 and (n & (n - 1)) == 0

Use two pointers: one for placing non-zero elements.

def moveZeroes(nums):
    pos = 0
    for i in range(len(nums)):
        if nums[i] != 0:
            nums[pos], nums[i] = nums[i], nums[pos]
            pos += 1

XOR all elements. Pairs cancel out, leaving the single number.

def singleNumber(nums):
    result = 0
    for num in nums:
        result ^= num
    return result

Use sets for O(n+m) time.

def intersection(a, b):
